logger.message:
#[%dw 2.0
				    output application/json
				    ---
				    { Contact: vars.queryData }
				  ]

ee:variables.ee:set-variable:
%dw 2.0 output text/plain var errorBody = { "Hello": vars.userEmailVar[0].Username, "Message": "This email is to notify you that an error occurred while attempting to " ++ payload.data.payload.ChangeEventHeader.changeType ++ " a Contact in NextGen.", "Contact Details": { "Timestamp": now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSSXXX"}, "ContactId": payload.data.payload.ChangeEventHeader.recordIds[0], "Contact Full Name": (vars.queryData[0].FirstName default "") ++ " " ++ (vars.queryData[0].LastName default ""), "Date of Birth": vars.queryData[0].Date_of_Birth__c default null, "Email": vars.queryData[0].Email default null, "Phone": vars.queryData[0].Phone default null, "Address": [ vars.queryData[0].MailingStreet default null, vars.queryData[0].MailingCity default null, vars.queryData[0].MailingState default null, vars.queryData[0].MailingCountry default null, vars.queryData[0].MailingPostalCode default null ] }, "UserID": payload.data.payload.ChangeEventHeader.commitUser, "Context": "The system encountered the above error while attempting to " ++ payload.data.payload.ChangeEventHeader.changeType ++ " the following Contact in NextGen. Please review the details and address the issue." }
--- "Hello: " ++ errorBody.Hello ++ " Message: " ++ errorBody.Message ++ "
Contact Details: - Timestamp: " ++ (errorBody.'Contact Details'.Timestamp as String {class: "null"} default "N/A") ++ " - ContactId: " ++ (errorBody.'Contact Details'.ContactId as String {class: "null"} default "N/A") ++ " - Contact Full Name: " ++ (errorBody.'Contact Details'.'Contact Full Name' as String {class: "null"} default "N/A") ++ " - Date of Birth: " ++ (errorBody.'Contact Details'.'Date of Birth' as String {class: "null"} default "N/A") ++ " - Email: " ++ (errorBody.'Contact Details'.Email as String {class: "null"} default "N/A") ++ " - Phone: " ++ (errorBody.'Contact Details'.Phone as String {class: "null"} default "N/A") ++ " - Address: " ++ (errorBody.'Contact Details'.Address filter $ != null joinBy ", " default "N/A") ++ " - UserID: " ++ (errorBody.UserID as String {class: "null"} default "N/A") ++ " - Context: " ++ (errorBody.Context as String {class: "null"} default "N/A")
